mapper.select:
SELECT H.hospital_name , C.center_name , HM.center_manager_code , sf_user_name(user_id) AS center_manager_name , HM.mobile , HM.telephone , HM.email , HM.user_id , HM.no_use , HM.notok_urge , HM.notok_updated_at FROM center_manager HM LEFT JOIN center C ON HM.center_id = C.center_id LEFT JOIN hospital H ON C.hospital_id = H.hospital_id WHERE HM.deleted_at IS NULL AND HM.notok_urge != 0
AND H.hospital_id = #{hospitalId}
AND C.center_id = #{centerId}
